blocks.body:
{
    "level": "A1",
    "intro": "Конструкції <strong>have got / has got</strong> допомагають сказати, <strong>що хтось має</strong>: річ, тварину, родича або іншу просту ознаку.",
    "rules": [
        {
            "label": "I / you / we / they",
            "color": "emerald",
            "text": "З цими підметами вживай <strong>have got</strong>.",
            "example": "I have got a book. / They have got a car."
        },
        {
            "label": "He / she / it",
            "color": "blue",
            "text": "З <strong>he / she / it</strong> вживай <strong>has got</strong>.",
            "example": "He has got a dog. / She has got a cat."
        },
        {
            "label": "Повні форми",
            "color": "amber",
            "text": "У негативі й питаннях на A1 легко триматися повних форм: <strong>have not got / has not got</strong>, <strong>Have ... got?</strong>, <strong>Has ... got?</strong>.",
            "example": "We have not got a house. / Has she got a cat?"
        }
    ]
}

{
    "title": "1. Базові форми",
    "intro": "Запам'ятай, яка форма йде з яким підметом.",
    "items": [
        {
            "label": "I / You / We / They",
            "title": "have got",
            "subtitle": "I have got a book. / They have got a car."
        },
        {
            "label": "He / She / It",
            "title": "has got",
            "subtitle": "He has got a dog. / She has got two books."
        },
        {
            "label": "Negative",
            "title": "have not got / has not got",
            "subtitle": "You have not got a cat. / He has not got a brother."
        },
        {
            "label": "Questions",
            "title": "Have / Has + subject + got",
            "subtitle": "Have you got a book? / Has she got a cat?"
        }
    ]
}

{
    "title": "2. Коли вживаємо have got / has got",
    "sections": [
        {
            "label": "Предмети та речі",
            "color": "emerald",
            "description": "Використовуй <strong>have got / has got</strong>, коли говориш про речі, які людина має.",
            "examples": [
                {
                    "en": "I have got a book.",
                    "ua": "У мене є книга."
                },
                {
                    "en": "They have got a car.",
                    "ua": "У них є машина."
                }
            ]
        },
        {
            "label": "Родина та тварини",
            "color": "blue",
            "description": "Конструкція часто описує родичів, домашніх тварин або людей поруч із нами.",
            "examples": [
                {
                    "en": "I have got a sister.",
                    "ua": "У мене є сестра."
                },
                {
                    "en": "She has got a cat.",
                    "ua": "У неї є кіт."
                }
            ]
        },
        {
            "label": "Заперечення та питання",
            "color": "amber",
            "description": "На A1 зручно тримати повні форми: <strong>have not got / has not got</strong> і питання з <strong>Have / Has</strong> на початку.",
            "examples": [
                {
                    "en": "He has not got a brother.",
                    "ua": "У нього немає брата."
                },
                {
                    "en": "What have you got?",
                    "ua": "Що в тебе є?"
                }
            ],
            "note": "📌 Після <strong>have / has</strong> у цій темі йде <strong>got</strong>."
        }
    ]
}

{
    "title": "3. Швидка таблиця",
    "intro": "Одна базова модель для кожного типу речення.",
    "rows": [
        {
            "en": "I / You / We / They",
            "ua": "have got",
            "note": "We have got a house."
        },
        {
            "en": "He / She / It",
            "ua": "has got",
            "note": "She has got two books."
        },
        {
            "en": "Negative",
            "ua": "have not got / has not got",
            "note": "I have not got a car. / He has not got a brother."
        },
        {
            "en": "Question",
            "ua": "Have / Has + subject + got?",
            "note": "Have they got a car? / Has he got a dog?"
        }
    ],
    "warning": "📌 На цьому рівні тримайся повних форм: <strong>have got, has got, have not got, has not got</strong>."
}

{
    "title": "4. Короткий підсумок",
    "items": [
        "З <strong>I / you / we / they</strong> використовуй <strong>have got</strong>.",
        "З <strong>he / she / it</strong> використовуй <strong>has got</strong>.",
        "Негатив: <strong>have not got / has not got</strong>.",
        "Питання: <strong>Have / Has + subject + got?</strong>",
        "Wh-питання теж будуються через <strong>have / has + subject + got</strong>: <strong>What have you got?</strong>, <strong>What has he got?</strong>"
    ]
}
